horizonData() {
    if(!state.settings.showHorizon) return;
    const sysToday = Utils.todayStr;

    state.lanes.forEach(lane => {
        const bin = document.getElementById(`overdue-bin-${lane.id}`);
        const sec = document.getElementById(`overdue-sec-${lane.id}`);
        if(bin && sec) {
            bin.innerHTML = '';
            const overdue = state.items.filter(i => i.laneId === lane.id && !i.isDone && i.dateStr && i.dateStr < sysToday);
            if (overdue.length > 0) {
                overdue.forEach(itemData => {
                    const itemEl = document.createElement('div');
                    itemEl.className = `item sl-${lane.id} ${itemData.type} is-clone is-overdue`;
                    itemEl.dataset.id = itemData.id;
                    itemEl.innerHTML = Render.itemHTML(itemData, { showProjectTag: true, isReadonly: true });
                    bin.appendChild(itemEl);
                });
                sec.style.display = 'block';
            } else { sec.style.display = 'none'; }
        }

        const container = document.getElementById(`hz-${lane.id}`);
        if(container) {
            container.innerHTML = ''; 
            const ul = document.createElement('ul'); ul.className = 'index-list';
            const hzItems = state.items.filter(i => { return i.laneId === lane.id && i.dateStr && (i.type === 'type-outcome' || i.type === 'type-milestone' || i.type === 'type-event') && (i.dateStr >= sysToday || i.isDone); });
            const mapped = hzItems.map(item => { if (!state.settings.showAchievements && item.isDone) return null; return { ...item, diffDays: Utils.getDiffDays(item.dateStr) }; }).filter(i => i !== null).sort((a, b) => a.diffDays - b.diffDays);

            mapped.forEach(data => {
                const li = document.createElement('li');
                const typeConfig = Config.itemTypes.find(t => t.id === data.type) || Config.itemTypes[0];

                let projBadge = '';
                if (data.projectId) {
                    const p = state.projects.find(x => x.id === data.projectId);
                    if (p) projBadge = `<span class="proj-tag" title="${Utils.escape(p.title)}">${Utils.escape(p.title.substring(0,2).toUpperCase())}</span>`;
                }

                li.dataset.date = data.dateStr; li.dataset.id = data.id; li.classList.add('hz-item', data.type, `sl-${lane.id}`); 
                if (data.type === 'type-milestone') li.classList.add('type-m-index');
                if (data.isDone) li.classList.add('is-done');
                let timeStr = data.diffDays > 0 ? `${data.diffDays}d` : (data.diffDays === 0 ? 'Today' : 'Past');

                li.innerHTML = `
                    <div style="display:flex; align-items:center; padding-left:10px;">
                        <span class="type-badge action-btn" role="button" tabindex="0" data-action="cycleType" style="margin-right: 8px;">${typeConfig.label}</span>
                        ${projBadge}
                    </div>
                    <span class="index-text action-btn" role="button" tabindex="0" data-action="seekToDate" data-val="${data.dateStr}" data-id="${data.id}">${Utils.escape(data.text)}</span>
                    <span class="index-days">${timeStr}</span>
                `;
                ul.appendChild(li);
            });
            container.appendChild(ul);
        }
    });
    this.applyScrollFilter(); this.syncHorizonHeight(); 
},

syncHorizonHeight() {
    const hz = DOM.horizon; if(!state.settings.showHorizon) { hz.style.height = ''; return; }
    hz.style.height = 'auto'; 
    const gridSize = 44;
    hz.style.height = (Math.ceil(hz.scrollHeight / gridSize) * gridSize) + 'px';
},

buildDayBlock(dateStr) {
    const curDate = Utils.parseDate(dateStr); 
    const dayName = curDate.toLocaleString('default', { weekday: 'short' });

