2006	        //   - seekToDate() handles "Today" button and Horizon click-throughs - if the target
2007	        //     date is already in the DOM it scrolls to it; otherwise it rebuilds the window
2008	        //     centred on that date.
2009	        //   - isVirtualizing lock prevents the observer from firing a second batch while one
2010	        //     is already being appended to the DOM.
2011	        const VirtualScroll = {
2012	            pendingForward: false, pendingBackward: false,
2013	            init() {
2014	                this.reset();
2015	                const observer = new IntersectionObserver((entries) => {
2016	                    entries.forEach(entry => {
2017	                        if(entry.isIntersecting) { if(entry.target.id === 'scroll-sentinel') this.pendingForward = true; if(entry.target.id === 'top-sentinel') this.pendingBackward = true; } 
2018	                        else { if(entry.target.id === 'scroll-sentinel') this.pendingForward = false; if(entry.target.id === 'top-sentinel') this.pendingBackward = false; }
2019	                    });
2020	                    if (!isVirtualizing) this.processPending();
2021	                }, { rootMargin: '400px' }); 
2022	                observer.observe(DOM.bottomSentinel); observer.observe(DOM.topSentinel);
2023	            },
2024	            processPending() {
2025	                if (isVirtualizing) return;
2026	                if (this.pendingForward) this.loadForward(30); else if (this.pendingBackward) this.loadBackward(30);
2027	            },
2028	            reset() {
2029	                renderStartDate = Utils.today; if (!state.settings.showAchievements) { renderStartDate.setDate(renderStartDate.getDate() - 1); } else { renderStartDate.setDate(renderStartDate.getDate() - 30); }
2030	                renderEndDate = new Date(renderStartDate.getTime()); renderEndDate.setDate(renderEndDate.getDate() - 1); 
2031	                this.loadForward(60); 
2032	            },
2033	            seekToDate(targetDateStr, highlightId = null) {
2034	                if (!targetDateStr) return; 
2035	                const target = Utils.parseDate(targetDateStr);
