//   - seekToDate() handles "Today" button and Horizon click-throughs - if the target
//     date is already in the DOM it scrolls to it; otherwise it rebuilds the window
//     centred on that date.
//   - isVirtualizing lock prevents the observer from firing a second batch while one
//     is already being appended to the DOM.
const VirtualScroll = {
    pendingForward: false, pendingBackward: false,
    init() {
        this.reset();
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if(entry.isIntersecting) { if(entry.target.id === 'scroll-sentinel') this.pendingForward = true; if(entry.target.id === 'top-sentinel') this.pendingBackward = true; } 
                else { if(entry.target.id === 'scroll-sentinel') this.pendingForward = false; if(entry.target.id === 'top-sentinel') this.pendingBackward = false; }
            });
            if (!isVirtualizing) this.processPending();
        }, { rootMargin: '400px' }); 
        observer.observe(DOM.bottomSentinel); observer.observe(DOM.topSentinel);
    },
    processPending() {
        if (isVirtualizing) return;
        if (this.pendingForward) this.loadForward(30); else if (this.pendingBackward) this.loadBackward(30);
    },
    reset() {
        renderStartDate = Utils.today; if (!state.settings.showAchievements) { renderStartDate.setDate(renderStartDate.getDate() - 1); } else { renderStartDate.setDate(renderStartDate.getDate() - 30); }
