1	/**
2	 * tests/smoke.js — Automated smoke tests for Swimlane_App.html
3	 *
4	 * Usage:
5	 *   node tests/smoke.js
6	 *
7	 * Covers the critical happy paths. Runs automatically via the Claude Code
8	 * Stop hook after every session that modifies the project.
9	 *
10	 * Tests:
11	 *   T1  Syntax check     — JS parses cleanly (fast, no browser)
12	 *   T2  Boot             — app loads, no JS errors, 60 day blocks render
13	 *   T3  Onboarding       — "Start Journaling" dismisses modal, reveals journal
14	 *   T4  Add item         — clicking today's track and typing creates an item
15	 *   T5  Search           — Ctrl+K opens the command palette
16	 *   T6  Undo             — Ctrl+Z removes the item added in T4
17	 *   T7  Persist          — data survives a page reload
18	 */
19	
20	const path = require('path');
21	const fs   = require('fs');
22	
23	// ── Locate Playwright ────────────────────────────────────────────────────────
24	function findPlaywright() {
25	    const cacheRoot = path.join(process.env.LOCALAPPDATA || '', 'npm-cache', '_npx');
26	    if (!fs.existsSync(cacheRoot)) return null;
27	    for (const entry of fs.readdirSync(cacheRoot)) {
28	        const candidate = path.join(cacheRoot, entry, 'node_modules', 'playwright');
29	        if (fs.existsSync(candidate)) return candidate;
30	    }
31	    return null;
32	}
33	
34	const playwrightPath = findPlaywright();
35	if (!playwrightPath) {
36	    console.error('ERROR: playwright not found. Run: npx playwright install chromium');
37	    process.exit(1);
38	}
39	
40	const { chromium } = require(playwrightPath);
41	
42	// ── Config ────────────────────────────────────────────────────────────────────
43	const HTML_FILE = path.resolve(__dirname, '..', 'Swimlane_App.html');
44	const FILE_URL  = 'file:///' + HTML_FILE.replace(/\\/g, '/');
45	const SCREENSHOT_DIR = path.join(__dirname, 'screenshots');
46	if (!fs.existsSync(SCREENSHOT_DIR)) fs.mkdirSync(SCREENSHOT_DIR);
47	
48	// ── Test runner ───────────────────────────────────────────────────────────────
49	const results = [];
50	let passed = 0, failed = 0;
51	
52	function record(name, ok, detail = '') {
53	    results.push({ name, ok, detail });
54	    if (ok) { passed++; console.log(`  ✔  ${name}`); }
55	    else     { failed++; console.log(`  ✖  ${name}${detail ? ': ' + detail : ''}`); }
56	}
57	
58	// ── T1: Syntax check (no browser) ────────────────────────────────────────────
59	function t1_syntax() {
60	    const html  = fs.readFileSync(HTML_FILE, 'utf8');
61	    const start = html.indexOf('<script>') + '<script>'.length;
62	    const end   = html.lastIndexOf('</script>');
63	    if (start < 0 || end < 0) { record('T1 Syntax check', false, 'No <script> block found'); return; }
64	    const tmpJs = path.join(__dirname, '_syntax_check_tmp.js');
65	    fs.writeFileSync(tmpJs, html.substring(start, end), 'utf8');
66	    const { execSync } = require('child_process');
67	    try {
68	        execSync(`node --check "${tmpJs}"`, { stdio: 'pipe' });
69	        record('T1 Syntax check', true);
70	    } catch (e) {
71	        record('T1 Syntax check', false, e.stderr?.toString().split('\n')[0] || 'parse error');
72	    } finally {
73	        fs.unlinkSync(tmpJs);
74	    }
75	}
76	
77	// ── Browser tests ─────────────────────────────────────────────────────────────
78	async function runBrowserTests() {
79	    const browser = await chromium.launch({ headless: true });
80	    const ctx     = await browser.newContext();
81	
82	    async function freshPage() {
83	        // Clear storage so every test starts from a known blank state
84	        await ctx.clearCookies();
85	        const page = await ctx.newPage();
86	        const errors = [];
87	        page.on('pageerror', e => errors.push(e.message));
88	        // Wipe IndexedDB and localStorage before loading
89	        await page.addInitScript(() => {
90	            indexedDB.deleteDatabase('swimlane_journal_v14');
91	            localStorage.clear();
92	        });
93	        return { page, errors };
94	    }
95	
96	    // ── T2: Boot ────────────────────────────────────────────────────────────
97	    {
98	        const { page, errors } = await freshPage();
99	        await page.goto(FILE_URL);
100	        await page.waitForTimeout(2500);
101	        const dayBlocks = await page.evaluate(() => document.querySelectorAll('.day-block').length);
102	        const noErrors  = errors.length === 0;
103	        record('T2 Boot (no JS errors, calendar renders)', noErrors && dayBlocks >= 30,
104	            !noErrors ? errors[0] : dayBlocks < 30 ? `only ${dayBlocks} day blocks` : '');
105	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't2-boot.png') });
106	        await page.close();
107	    }
108	
109	    // ── T3: Onboarding dismissal ─────────────────────────────────────────────
110	    {
111	        const { page, errors } = await freshPage();
112	        await page.goto(FILE_URL);
113	        await page.waitForTimeout(1500);
114	        const overlayVisible = await page.evaluate(() => {
115	            const o = document.getElementById('onboarding-overlay');
116	            return o && o.classList.contains('is-open');
117	        });
118	        if (overlayVisible) {
119	            await page.click('[data-action="closeOnboarding"]');
120	            await page.waitForTimeout(500);
121	        }
122	        const overlayClosed = await page.evaluate(() => {
123	            const o = document.getElementById('onboarding-overlay');
124	            return !o || !o.classList.contains('is-open');
125	        });
126	        const journalVisible = await page.evaluate(() => {
127	            const c = document.getElementById('journal-container');
128	            return c && c.innerHTML.length > 1000;
129	        });
130	        record('T3 Onboarding dismissal', overlayClosed && journalVisible,
131	            !overlayClosed ? 'overlay still open' : !journalVisible ? 'journal not rendered' : '');
132	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't3-onboarding.png') });
133	        await page.close();
134	    }
135	
136	    // ── T4: Add item ─────────────────────────────────────────────────────────
137	    // Clicks the first visible lane track on today's row and types a task.
138	    {
139	        const { page, errors } = await freshPage();
140	        await page.goto(FILE_URL);
141	        await page.waitForTimeout(1500);
142	        // Dismiss onboarding if present
143	        const hasOnboarding = await page.evaluate(() =>
144	            document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
145	        if (hasOnboarding) await page.click('[data-action="closeOnboarding"]');
146	        await page.waitForTimeout(500);
147	
148	        // Click today's first track cell (the add-item area)
149	        const todayTrack = await page.$('.is-today .track');
150	        let itemAdded = false;
151	        if (todayTrack) {
152	            await todayTrack.click();
153	            await page.waitForTimeout(400);
154	            // If an input appeared, type in it
155	            const input = await page.$('.item-input, .new-item-input, input[data-role="new-item"]');
156	            if (input) {
157	                await input.type('Smoke test task');
158	                await page.keyboard.press('Enter');
159	                await page.waitForTimeout(400);
160	            }
161	            // Check item exists in DOM or state
162	            itemAdded = await page.evaluate(() =>
163	                document.querySelectorAll('.is-today .item[data-id]').length > 0
164	            );
165	        }
166	        record('T4 Add item', itemAdded, !todayTrack ? 'today track not found' : !itemAdded ? 'item not in state' : '');
167	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't4-add-item.png') });
168	        await page.close();
169	    }
170	
171	    // ── T5: Search (Ctrl+K) ──────────────────────────────────────────────────
172	    {
173	        const { page, errors } = await freshPage();
174	        await page.goto(FILE_URL);
175	        await page.waitForTimeout(1500);
176	        const hasOnboarding = await page.evaluate(() =>
177	            document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
178	        if (hasOnboarding) await page.click('[data-action="closeOnboarding"]');
179	        await page.waitForTimeout(300);
180	
181	        await page.keyboard.press('Control+k');
182	        await page.waitForTimeout(400);
183	        const paletteOpen = await page.evaluate(() => {
184	            const p = document.getElementById('search-overlay');
185	            return p && (p.style.display !== 'none') && p.offsetHeight > 0;
186	        });
187	        record('T5 Search (Ctrl+K)', paletteOpen, paletteOpen ? '' : 'search overlay not visible');
188	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't5-search.png') });
189	        await page.close();
190	    }
191	
192	    // ── T6: Undo (Ctrl+Z) ────────────────────────────────────────────────────
193	    // Inject an item directly via App.Actions, then undo it.
194	    {
195	        const { page, errors } = await freshPage();
196	        await page.goto(FILE_URL);
197	        await page.waitForTimeout(1500);
198	        const hasOnboarding = await page.evaluate(() =>
199	            document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
200	        if (hasOnboarding) await page.click('[data-action="closeOnboarding"]');
201	        await page.waitForTimeout(300);
202	
203	        // Add item via App.Actions if accessible
204	        const addedAndUndone = await page.evaluate(async () => {
205	            if (!window.App || !window.App.state) return null;
206	            const before = window.App.state.items.length;
207	            const laneId = window.App.state.lanes[0]?.id;
208	            const today  = new Date().toISOString().split('T')[0];
209	            if (!laneId) return null;
210	            window.App.addItem && window.App.addItem(laneId, today, 'undo-test-item');
211	            await new Promise(r => setTimeout(r, 300));
212	            const after = window.App.state.items.length;
213	            return { before, after };
214	        });
215	
216	        if (addedAndUndone && addedAndUndone.after > addedAndUndone.before) {
217	            await page.keyboard.press('Control+z');
218	            await page.waitForTimeout(400);
219	            const afterUndo = await page.evaluate(() => window.App?.state?.items?.length ?? -1);
220	            record('T6 Undo (Ctrl+Z)', afterUndo <= addedAndUndone.before,
221	                `items: before=${addedAndUndone.before} after-add=${addedAndUndone.after} after-undo=${afterUndo}`);
222	        } else {
223	            // Can't inject via API — just verify Ctrl+Z doesn't crash
224	            await page.keyboard.press('Control+z');
225	            await page.waitForTimeout(400);
226	            const noError = errors.length === 0;
227	            record('T6 Undo (Ctrl+Z)', noError, noError ? '(API not exposed; verified no crash)' : errors[0]);
228	        }
229	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't6-undo.png') });
230	        await page.close();
231	    }
232	
233	    // ── T7: Persistence ──────────────────────────────────────────────────────
234	    // Load, inject state, reload, verify state survived.
235	    {
236	        const { page, errors } = await freshPage();
237	        await page.goto(FILE_URL);
238	        await page.waitForTimeout(1500);
239	        const hasOnboarding = await page.evaluate(() =>
240	            document.getElementById('onboarding-overlay')?.classList.contains('is-open'));
241	        if (hasOnboarding) await page.click('[data-action="closeOnboarding"]');
242	        await page.waitForTimeout(300);
243	
244	        const initialLaneCount = await page.evaluate(() => window.App?.state?.lanes?.length ?? 0);
245	        const reloadErrors = [];
246	        page.on('pageerror', e => reloadErrors.push(e.message));
247	        await page.reload();
248	        await page.waitForTimeout(2000);
249	        const afterReloadLaneCount = await page.evaluate(() => window.App?.state?.lanes?.length ?? 0);
250	        const reloadedOk = reloadErrors.length === 0 && afterReloadLaneCount >= initialLaneCount;
251	        record('T7 Persist (reload)', reloadedOk,
252	            reloadErrors.length ? reloadErrors[0] : !reloadedOk ? `lanes ${initialLaneCount}→${afterReloadLaneCount}` : '');
253	        await page.screenshot({ path: path.join(SCREENSHOT_DIR, 't7-persist.png') });
254	        await page.close();
255	    }
256	
257	    await browser.close();
258	}
259	
260	// ── Main ──────────────────────────────────────────────────────────────────────
261	const HR = '─'.repeat(60);
262	console.log(`\n${HR}`);
263	console.log('  Swimlane Smoke Tests');
264	console.log(HR);
265	
266	t1_syntax();
267	
268	runBrowserTests().then(() => {
269	    console.log(HR);
270	    console.log(`  ${passed + failed} tests   ✔ ${passed} passed   ${failed > 0 ? '✖' : '·'} ${failed} failed`);
271	    console.log(`  Screenshots: tests/screenshots/`);
272	    console.log(HR + '\n');
273	    process.exit(failed > 0 ? 1 : 0);
274	}).catch(err => {
275	    console.error('Fatal error:', err.message);
276	    process.exit(1);
277	});
