document.addEventListener('input', (e) => {
    if(e.target.classList.contains('action-input')) {
        const action = e.target.dataset.action;
        if(action === 'editLaneTitle') Actions.updateLaneTitle(e.target.dataset.id, e.target.value);
        if(action === 'editDiary') Actions.updateDiary(e.target.dataset.date, e.target.value);
        if(action === 'editTask') {
            const id = e.target.closest('.item').dataset.id;
            document.querySelectorAll(`.item[data-id="${id}"] .text-input`).forEach(el => { if(el !== e.target) el.value = e.target.value; });
            clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateTaskText(id, e.target.value), 300);
        }
        if(action === 'editTaskNoteContent') {
            const itemEl = e.target.closest('.item');
            const id = itemEl.dataset.id;
            clearTimeout(e.target._saveTimer); 
            e.target._saveTimer = setTimeout(() => Actions.updateTaskNote(id, e.target.innerHTML), 300);
            Render.snapItemHeight(itemEl);
        }
        if(action === 'editNoteTitle') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateNoteTitle(uiState.activeNoteId, e.target.value), 200); }
        if(action === 'editNoteBody') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateNoteBody(uiState.activeNoteId, e.target.innerHTML), 300); }
        if(action === 'editProjectTitle') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateProjectTitle(uiState.activeProjectId, e.target.value), 200); }
    }
});

document.addEventListener('change', (e) => {
    if(e.target.dataset.action === 'editProjTaskDate') { 
        const id = e.target.closest('[data-id]').dataset.id;
        Actions.editItemDate(id, e.target.value); 
    }
});

document.addEventListener('selectionchange', () => {
    if(document.activeElement === DOM.noteBodyInput || (document.activeElement && document.activeElement.classList.contains('item-note-body'))) {
        document.querySelectorAll('#btn-bold, .fmt-btn-mini[title="Bold"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('bold')));
        document.querySelectorAll('#btn-italic, .fmt-btn-mini[title="Italic"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('italic')));
        document.querySelectorAll('#btn-list, .fmt-btn-mini[title="List"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('insertUnorderedList')));
    }
});

document.addEventListener('focusout', (e) => {
    if(e.target.classList.contains('action-contenteditable')) { const val = e.target.innerText.trim(); Actions.updateHabitTitle(e.target.dataset.id, val); e.target.innerText = val || 'Habit'; }

