// ─── EVENTBUS ─────────────────────────────────────────────────────────────
// A lightweight Publish / Subscribe message bus that decouples Actions from Render.
//
// How it works:
//   1. Render.init() calls EventBus.on('someEvent', handler) to register listeners.
//   2. Actions call EventBus.emit('someEvent', payload) after mutating State.
//   3. The bus calls every registered handler - Render reacts without Actions needing
//      to know anything about the DOM.
//
// clear() is called at the start of hardRebuild() to flush stale listeners before
// Render.init() re-registers them, preventing duplicate handler accumulation.
const EventBus = {
    listeners: {},
    on(event, cb) { if(!this.listeners[event]) this.listeners[event] = []; this.listeners[event].push(cb); },
    off(event, cb) { if(this.listeners[event]) this.listeners[event] = this.listeners[event].filter(l => l !== cb); },
    clear() { this.listeners = {}; },
    emit(event, data) { if(this.listeners[event]) this.listeners[event].forEach(cb => cb(data)); }
};

// ─── UNDO ─────────────────────────────────────────────────────────────────
// Snapshot-based undo. Before any destructive action, snap() deep-clones the
// entire State object and pushes it onto the stack (max 20 entries - the oldest
// is dropped when the stack fills up to keep memory bounded).
//
// perform() pops the last snapshot, replaces the live State with it, saves to
// storage, and triggers a full DOM rebuild - effectively rolling the app back in time.
//
// showSystemToast() briefly displays a notification strip at the top of the screen
// so the user can see what was undone.
let undoTimer;
const Undo = {
    stack: [], max: 20,
    // INPUT: label - human-readable name of the action being snapshotted (e.g. 'Add Lane')
    // ALGO:  deep-clone State via JSON round-trip (cheap and reliable for plain objects)
    // OUTPUT: new entry pushed onto stack; oldest entry trimmed if over limit
    snap(label = 'Action') {
        this.stack.push({ label, stateData: JSON.parse(JSON.stringify(state)) });
        if(this.stack.length > this.max) this.stack.shift();
    },
    // INPUT: none
    // ALGO:  pop last snapshot, overwrite live State, persist, rebuild UI
    // OUTPUT: app visually rolls back to the previous state; toast shown
    perform() {
        if(!this.stack.length) return;
        const snap = this.stack.pop();
        state = snap.stateData;
        Store.save(); applySettings(); Render.hardRebuild();
        if(uiState.isProjectsOpen) Render.projectsDrawerUI();
        if(uiState.isNotesOpen) Render.notesDrawerUI();
        this.showSystemToast('Undid: ' + snap.label, true);
    },
    showSystemToast(msg, showUndoBtn = false) {
        document.getElementById('undo-msg').innerText = msg;
        document.getElementById('undo-btn').style.display = showUndoBtn ? 'block' : 'none';
        DOM.toast.classList.add('is-active');
        clearTimeout(undoTimer); undoTimer = setTimeout(() => DOM.toast.classList.remove('is-active'), 3500);
    }
};

