/* ================= HORIZON ================= */
.journal-horizon {
    display: none; background: rgba(253, 251, 247, 0.98);
    box-shadow: inset 0 3px 5px rgba(0,0,0,0.02), 0 10px 15px -3px rgba(0,0,0,0.1), 0 2px 0 0 var(--text-color);
    position: sticky; top: 132px; z-index: 45; max-height: 55vh; overflow-y: auto; padding-bottom: 10px;
}
.journal-horizon.is-expanded { display: grid; }
.horizon-col { padding: 0 15px 15px 15px; display: flex; flex-direction: column;}

.overdue-section { display: none; margin-bottom: 0; }
.overdue-header { 
    font-family: var(--font-ui); color: #ef4444; font-size: 28px; font-weight: bold; margin: 0 0 8px 0;
    height: var(--grid-size); line-height: var(--grid-size); box-shadow: 0 1px 0 dashed #fca5a5;
}
.overdue-bin { display: flex; flex-direction: column; min-height: 10px;}

.index-list { list-style: none; padding: 0; margin: 0; font-family: var(--font-ui); font-size: 24px; font-weight: 500;}
.hz-item { 
    display: flex; flex-direction: row; justify-content: flex-start; align-items: center;
    height: var(--grid-size); line-height: var(--grid-size); box-shadow: 0 1px 0 dotted #e5e5e5; padding: 0; width: 100%;
}
.hz-item.is-done .index-text { text-decoration: line-through; opacity: 0.5; color: #94a3b8; }
.index-text { flex: 1; min-width: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; cursor: pointer; padding-right: 10px;}
.index-days { font-family: var(--font-ui); font-weight: bold; color: #ef4444; font-size: 24px; padding-right: 8px; flex-shrink: 0;} 
.type-m-index .index-days { color: #854d0e; }

