updateDiary(d, val) { this.mutate(() => { if(val.trim()==='') delete state.diary[d]; else state.diary[d] = val; }, 'silentSave'); },

toggleFocusTimer(dateStr) {
    if (dateStr !== Utils.todayStr) return; 
    this.mutate(() => {
        if (!state.focus[dateStr]) state.focus[dateStr] = { sessions: [], startTs: null };
        const f = state.focus[dateStr];
        const now = Date.now();
        if (f.startTs) { f.sessions.push({ s: f.startTs, e: now }); f.startTs = null; } 
        else { f.startTs = now; }
    }, 'focusChanged');
},

showFocusStats(dateStr) {
    const f = state.focus[dateStr];
    if (!f || (f.sessions.length === 0 && !f.startTs)) return;

    let html = '';
    let totalTime = 0; let firstS = null; let lastE = null;
    const now = Date.now();
    const renderSessions = [...f.sessions];
    if (f.startTs) renderSessions.push({ s: f.startTs, e: now });

    renderSessions.forEach(s => {
        totalTime += (s.e - s.s);
        if (!firstS || s.s < firstS) firstS = s.s;
        if (!lastE || s.e > lastE) lastE = s.e;
        html += `<div class="focus-stat-row"><span>${Utils.formatTimeClock(new Date(s.s))} - ${Utils.formatTimeClock(new Date(s.e))}</span><span style="color:#64748b; font-size:14px;">${Utils.formatTime(s.e - s.s)}</span></div>`;
    });

    let elapsed = lastE - firstS;
    let score = elapsed > 0 ? Math.round((totalTime / elapsed) * 100) : 0;
    if (score > 100) score = 100;

    let out = `<div class="focus-stat-title">Date: ${dateStr}</div>`;
    out += `<div class="focus-stat-row" style="margin-top:10px;"><span>Total Focus Time:</span> <span style="color:#0f172a;">${Utils.formatTime(totalTime)}</span></div>`;
    out += `<div class="focus-stat-row"><span>Elapsed Time:</span> <span style="color:#64748b;">${Utils.formatTime(elapsed)}</span></div>`;
    out += `<div class="focus-stat-title" style="margin-top:20px;">Productivity Score</div>`;
    out += `<div class="focus-score">${score}%</div>`;

